using System.Collections.Generic;
using TMPro;
using UnityEngine;
using UnityEngine.Serialization;
using UnityEngine.UI;

/// <summary>
/// Secção "Área Atual" do Menu de Pausa (Tarefa #7) — substitui por completo o
/// antigo Mapa Local.
///
/// Mostra APENAS o que existe na área e quanto o jogador já encontrou. NUNCA
/// mostra: caminhos, salas, posição do jogador, entradas, locais secretos,
/// direcções de objectivos, posições de Runas/NPCs/baús, dicas automáticas ou
/// o animal recomendado para segredos.
///
/// Conteúdo (ver AreaData + PlayerProgress.AreaProgress):
/// - Nome da área, mundo a que pertence, descrição atmosférica, ilustração ambiente.
/// - DESCOBERTAS: Runas de Gaia, NPCs resgatados, Sussurros da Terra, Baús
///   encontrados, Fragmentos Vitais — cada linha só aparece se
///   AreaData.totalX > 0 (a área tem esse tipo de colecionável).
/// - Desafio da área: "?" até <see cref="PlayerProgress.IsChallengeDiscovered"/>,
///   depois "Não concluído"/"Concluído".
/// - Animal libertado: "?" até o animal estar em PlayerProgress.freedAnimalIds.
/// - Conclusão da área (%) — a 100% mostra "ÁREA RESTAURADA — 100%" com aura.
/// - "SUSSURROS DA TERRA": frases exactas (ditas por NPCs) já ouvidas sobre
///   esta área — ver Action_AddAreaSussurroDaTerra (mesma colecionável da
///   contagem "Sussurros da Terra" nas Descobertas). Se nenhuma, mostra a
///   frase de "nenhum sussurro ouvido".
/// </summary>
public class AreaSectionUI : MonoBehaviour, IPauseMenuSection
{
    [Header("Framework")]
    [SerializeField] private GameObject root;

    [Header("Cabeçalho da Secção")]
    [SerializeField] private TMP_Text areaNameText;
    [SerializeField] private TMP_Text worldNameText;
    [SerializeField] private TMP_Text descriptionText;
    [SerializeField] private Image illustrationImage;

    [Header("Descobertas — Runas de Gaia")]
    [SerializeField] private GameObject runasRow;
    [SerializeField] private TMP_Text runasText;
    [SerializeField] private string runasLabel = "Runas de Gaia";

    [Header("Descobertas — NPCs Resgatados")]
    [SerializeField] private GameObject npcsRow;
    [SerializeField] private TMP_Text npcsText;
    [SerializeField] private string npcsLabel = "NPCs resgatados";

    [Header("Descobertas — Sussurros da Terra")]
    [SerializeField] private GameObject whispersRow;
    [SerializeField] private TMP_Text whispersText;
    [SerializeField] private string whispersLabel = "Sussurros da Terra";

    [Header("Descobertas — Baús")]
    [SerializeField] private GameObject chestsRow;
    [SerializeField] private TMP_Text chestsText;
    [SerializeField] private string chestsLabel = "Baús encontrados";

    [Header("Descobertas — Fragmentos Vitais")]
    [SerializeField] private GameObject fragmentsRow;
    [SerializeField] private TMP_Text fragmentsText;
    [SerializeField] private string fragmentsLabel = "Fragmentos Vitais";

    [Header("Desafio da Área")]
    [SerializeField] private GameObject challengeRow;
    [SerializeField] private TMP_Text challengeText;
    [SerializeField] private string challengeLabel = "Desafio da área";
    [SerializeField] private string challengeUnknown = "?";
    [SerializeField] private string challengeNotDone = "Não concluído";
    [SerializeField] private string challengeDone = "Concluído";

    [Header("Animal Libertado")]
    [SerializeField] private GameObject freedAnimalRow;
    [SerializeField] private TMP_Text freedAnimalText;
    [SerializeField] private string freedAnimalLabel = "Animal libertado";
    [SerializeField] private string freedAnimalUnknown = "?";

    [Header("Conclusão da Área")]
    [SerializeField] private TMP_Text completionText;
    [SerializeField] private string completionFormat = "Conclusão da área {0}%";

    [Tooltip("Mostrado em vez do texto normal quando a área chega a 100% (ex: \"ÁREA RESTAURADA — 100%\").")]
    [SerializeField] private string restoredText = "ÁREA RESTAURADA — 100%";

    [Tooltip("Activado quando a área está a 100% — efeito de moldura a florescer/aura permanente.")]
    [SerializeField] private GameObject restoredAuraEffect;

    [Header("Sussurros da Terra — Frases Ouvidas")]
    [FormerlySerializedAs("echoesTitleText")]
    [SerializeField] private TMP_Text sussurrosTitleText;
    [FormerlySerializedAs("echoesTitle")]
    [SerializeField] private string sussurrosTitle = "SUSSURROS DA TERRA";
    [FormerlySerializedAs("echoesContainer")]
    [SerializeField] private Transform sussurrosContainer;
    [FormerlySerializedAs("echoLinePrefab")]
    [SerializeField] private TMP_Text sussurroLinePrefab;
    [FormerlySerializedAs("noEchoesText")]
    [SerializeField] private string noSussurrosText = "Nenhum sussurro da terra foi ouvido neste lugar.";

    private readonly List<GameObject> spawnedSussurroLines = new List<GameObject>();

    public string SectionName => "ÁREA";
    public GameObject Root => root != null ? root : gameObject;

    public void Refresh()
    {
        var area = WorldState.Instance != null ? WorldState.Instance.CurrentArea : null;
        var progress = PlayerProgress.Instance;

        if (area == null)
        {
            ClearAll();
            return;
        }

        if (areaNameText != null) areaNameText.text = area.displayName;
        if (worldNameText != null) worldNameText.text = area.world != null ? area.world.displayName : string.Empty;
        if (descriptionText != null) descriptionText.text = area.description;

        if (illustrationImage != null)
        {
            illustrationImage.sprite = area.illustration;
            illustrationImage.enabled = area.illustration != null;
        }

        SetupCountRow(runasRow, runasText, runasLabel, area.totalRunas, progress != null ? progress.GetRunasFound(area) : 0);
        SetupCountRow(npcsRow, npcsText, npcsLabel, area.totalNpcsToRescue, progress != null ? progress.GetNpcsRescued(area) : 0);
        SetupCountRow(whispersRow, whispersText, whispersLabel, area.totalWhispers, progress != null ? progress.GetWhispersFound(area) : 0);
        SetupCountRow(chestsRow, chestsText, chestsLabel, area.totalChests, progress != null ? progress.GetChestsFound(area) : 0);
        SetupCountRow(fragmentsRow, fragmentsText, fragmentsLabel, area.totalFragments, progress != null ? progress.GetFragmentsFound(area) : 0);

        SetupChallengeRow(area, progress);
        SetupFreedAnimalRow(area, progress);
        SetupCompletion(area, progress);
        SetupSussurros(area, progress);
    }

    public void OnHide()
    {
        // Sem estado próprio a limpar — Refresh() repõe tudo na próxima vez.
    }

    // ---------------- Linhas de Descobertas ----------------

    private void SetupCountRow(GameObject row, TMP_Text text, string label, int total, int found)
    {
        if (row != null) row.SetActive(total > 0);
        if (total <= 0 || text == null) return;

        text.text = $"{label} {Mathf.Min(found, total)}/{total}";
    }

    private void SetupChallengeRow(AreaData area, PlayerProgress progress)
    {
        if (challengeRow != null) challengeRow.SetActive(area.hasOptionalChallenge);
        if (!area.hasOptionalChallenge || challengeText == null) return;

        bool discovered = progress != null && progress.IsChallengeDiscovered(area);
        bool completed = progress != null && progress.IsChallengeCompleted(area);

        string status = !discovered ? challengeUnknown : (completed ? challengeDone : challengeNotDone);
        challengeText.text = $"{challengeLabel}: {status}";
    }

    private void SetupFreedAnimalRow(AreaData area, PlayerProgress progress)
    {
        bool hasAnimal = area.freedAnimalForm != null;
        if (freedAnimalRow != null) freedAnimalRow.SetActive(hasAnimal);
        if (!hasAnimal || freedAnimalText == null) return;

        bool freed = progress != null && progress.freedAnimalIds.Contains(area.freedAnimalForm.formId);
        string status = freed ? area.freedAnimalForm.displayName : freedAnimalUnknown;
        freedAnimalText.text = $"{freedAnimalLabel}: {status}";
    }

    // ---------------- Conclusão ----------------

    private void SetupCompletion(AreaData area, PlayerProgress progress)
    {
        int percent = progress != null ? progress.GetAreaCompletionPercent(area) : 0;
        bool restored = percent >= 100;

        if (completionText != null)
            completionText.text = restored ? restoredText : string.Format(completionFormat, percent);

        if (restoredAuraEffect != null) restoredAuraEffect.SetActive(restored);
    }

    // ---------------- Sussurros da Terra (frases ouvidas) ----------------

    private void SetupSussurros(AreaData area, PlayerProgress progress)
    {
        if (sussurrosTitleText != null) sussurrosTitleText.text = sussurrosTitle;

        ClearSussurroLines();

        var sussurros = progress != null ? progress.GetSussurrosDaTerraOuvidos(area) : null;

        if (sussurros == null || sussurros.Count == 0)
        {
            if (sussurroLinePrefab != null && sussurrosContainer != null)
            {
                var line = Instantiate(sussurroLinePrefab, sussurrosContainer);
                line.gameObject.SetActive(true);
                line.text = noSussurrosText;
                spawnedSussurroLines.Add(line.gameObject);
            }

            return;
        }

        if (sussurroLinePrefab == null || sussurrosContainer == null) return;

        foreach (var phrase in sussurros)
        {
            var line = Instantiate(sussurroLinePrefab, sussurrosContainer);
            line.gameObject.SetActive(true);
            line.text = $"“{phrase}”";
            spawnedSussurroLines.Add(line.gameObject);
        }
    }

    private void ClearSussurroLines()
    {
        foreach (var go in spawnedSussurroLines)
            if (go != null) Destroy(go);

        spawnedSussurroLines.Clear();
    }

    private void ClearAll()
    {
        if (areaNameText != null) areaNameText.text = string.Empty;
        if (worldNameText != null) worldNameText.text = string.Empty;
        if (descriptionText != null) descriptionText.text = string.Empty;
        if (illustrationImage != null) illustrationImage.enabled = false;

        if (runasRow != null) runasRow.SetActive(false);
        if (npcsRow != null) npcsRow.SetActive(false);
        if (whispersRow != null) whispersRow.SetActive(false);
        if (chestsRow != null) chestsRow.SetActive(false);
        if (fragmentsRow != null) fragmentsRow.SetActive(false);
        if (challengeRow != null) challengeRow.SetActive(false);
        if (freedAnimalRow != null) freedAnimalRow.SetActive(false);

        if (completionText != null) completionText.text = string.Empty;
        if (restoredAuraEffect != null) restoredAuraEffect.SetActive(false);

        ClearSussurroLines();
    }
}
